CREATE TYPE "BetaAccessStatus" AS ENUM ('INVITED', 'ACTIVE', 'WAITLISTED', 'SUSPENDED', 'EXPIRED');
CREATE TYPE "WaitlistStatus" AS ENUM ('PENDING', 'APPROVED', 'REJECTED', 'INVITED');
CREATE TYPE "FeedbackCategory" AS ENUM ('BUG', 'USABILITY', 'FEATURE_SUGGESTION', 'CONTENT_ISSUE', 'COLLEGE_DATA_ISSUE', 'MODERATION_CONCERN', 'OTHER');
CREATE TYPE "FeedbackStatus" AS ENUM ('NEW', 'TRIAGED', 'PLANNED', 'IN_PROGRESS', 'RESOLVED', 'DECLINED');
CREATE TYPE "AnnouncementAudience" AS ENUM ('ALL_USERS', 'BETA_USERS', 'MODERATORS', 'ADMINS');
ALTER TABLE "User" ADD COLUMN "betaActivatedAt" TIMESTAMP(3), ADD COLUMN "betaStatus" "BetaAccessStatus" NOT NULL DEFAULT 'WAITLISTED';
UPDATE "User" SET "betaStatus" = 'ACTIVE', "betaActivatedAt" = COALESCE("createdAt", CURRENT_TIMESTAMP);

CREATE TABLE "BetaInvite" ("id" TEXT NOT NULL,"codeHash" TEXT NOT NULL,"label" TEXT,"creatorId" TEXT NOT NULL,"expiresAt" TIMESTAMP(3),"maxUses" INTEGER NOT NULL DEFAULT 1,"usageCount" INTEGER NOT NULL DEFAULT 0,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "BetaInvite_pkey" PRIMARY KEY ("id"));
CREATE TABLE "BetaInviteRedemption" ("id" TEXT NOT NULL,"inviteId" TEXT NOT NULL,"userId" TEXT NOT NULL,"redeemedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "BetaInviteRedemption_pkey" PRIMARY KEY ("id"));
CREATE TABLE "BetaWaitlist" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"email" TEXT NOT NULL,"collegeInterest" TEXT,"reason" TEXT,"status" "WaitlistStatus" NOT NULL DEFAULT 'PENDING',"internalNote" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "BetaWaitlist_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Feedback" ("id" TEXT NOT NULL,"submitterId" TEXT NOT NULL,"category" "FeedbackCategory" NOT NULL,"title" TEXT NOT NULL,"description" TEXT NOT NULL,"currentPage" TEXT,"browserContext" TEXT,"status" "FeedbackStatus" NOT NULL DEFAULT 'NEW',"assignedAdminId" TEXT,"duplicateOfId" TEXT,"internalNote" TEXT,"resolutionSummary" TEXT,"resolvedAt" TIMESTAMP(3),"idempotencyKey" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Feedback_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FeedbackStatusHistory" ("id" TEXT NOT NULL,"feedbackId" TEXT NOT NULL,"status" "FeedbackStatus" NOT NULL,"actorId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "FeedbackStatusHistory_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FeatureFlag" ("id" TEXT NOT NULL,"key" TEXT NOT NULL,"enabled" BOOLEAN NOT NULL,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "FeatureFlag_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ReleaseRecord" ("id" TEXT NOT NULL,"version" TEXT NOT NULL,"releaseDate" TIMESTAMP(3) NOT NULL,"migrationVersion" TEXT NOT NULL,"buildIdentifier" TEXT,"environment" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ReleaseRecord_pkey" PRIMARY KEY ("id"));
CREATE TABLE "BetaAnnouncement" ("id" TEXT NOT NULL,"title" TEXT NOT NULL,"message" TEXT NOT NULL,"startsAt" TIMESTAMP(3) NOT NULL,"expiresAt" TIMESTAMP(3),"audience" "AnnouncementAudience" NOT NULL,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "BetaAnnouncement_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AnnouncementDismissal" ("id" TEXT NOT NULL,"announcementId" TEXT NOT NULL,"userId" TEXT NOT NULL,"dismissedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AnnouncementDismissal_pkey" PRIMARY KEY ("id"));
CREATE TABLE "GuidanceDismissal" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"guidanceKey" TEXT NOT NULL,"dismissedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "GuidanceDismissal_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "BetaInvite_codeHash_key" ON "BetaInvite"("codeHash"); CREATE INDEX "BetaInvite_active_expiresAt_idx" ON "BetaInvite"("active", "expiresAt");
CREATE UNIQUE INDEX "BetaInviteRedemption_userId_key" ON "BetaInviteRedemption"("userId"); CREATE INDEX "BetaInviteRedemption_inviteId_redeemedAt_idx" ON "BetaInviteRedemption"("inviteId", "redeemedAt");
CREATE UNIQUE INDEX "BetaWaitlist_email_key" ON "BetaWaitlist"("email"); CREATE INDEX "BetaWaitlist_status_createdAt_idx" ON "BetaWaitlist"("status", "createdAt");
CREATE UNIQUE INDEX "Feedback_idempotencyKey_key" ON "Feedback"("idempotencyKey"); CREATE INDEX "Feedback_status_category_createdAt_idx" ON "Feedback"("status", "category", "createdAt"); CREATE INDEX "Feedback_submitterId_createdAt_idx" ON "Feedback"("submitterId", "createdAt"); CREATE INDEX "Feedback_assignedAdminId_status_idx" ON "Feedback"("assignedAdminId", "status");
CREATE INDEX "FeedbackStatusHistory_feedbackId_createdAt_idx" ON "FeedbackStatusHistory"("feedbackId", "createdAt"); CREATE UNIQUE INDEX "FeatureFlag_key_key" ON "FeatureFlag"("key"); CREATE UNIQUE INDEX "ReleaseRecord_version_key" ON "ReleaseRecord"("version");
CREATE INDEX "BetaAnnouncement_active_startsAt_expiresAt_idx" ON "BetaAnnouncement"("active", "startsAt", "expiresAt"); CREATE UNIQUE INDEX "AnnouncementDismissal_announcementId_userId_key" ON "AnnouncementDismissal"("announcementId", "userId"); CREATE UNIQUE INDEX "GuidanceDismissal_userId_guidanceKey_key" ON "GuidanceDismissal"("userId", "guidanceKey");
ALTER TABLE "BetaInvite" ADD CONSTRAINT "BetaInvite_creatorId_fkey" FOREIGN KEY ("creatorId") REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "BetaInviteRedemption" ADD CONSTRAINT "BetaInviteRedemption_inviteId_fkey" FOREIGN KEY ("inviteId") REFERENCES "BetaInvite"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "BetaInviteRedemption" ADD CONSTRAINT "BetaInviteRedemption_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Feedback" ADD CONSTRAINT "Feedback_submitterId_fkey" FOREIGN KEY ("submitterId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "Feedback" ADD CONSTRAINT "Feedback_assignedAdminId_fkey" FOREIGN KEY ("assignedAdminId") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "Feedback" ADD CONSTRAINT "Feedback_duplicateOfId_fkey" FOREIGN KEY ("duplicateOfId") REFERENCES "Feedback"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "FeedbackStatusHistory" ADD CONSTRAINT "FeedbackStatusHistory_feedbackId_fkey" FOREIGN KEY ("feedbackId") REFERENCES "Feedback"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "FeedbackStatusHistory" ADD CONSTRAINT "FeedbackStatusHistory_actorId_fkey" FOREIGN KEY ("actorId") REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "AnnouncementDismissal" ADD CONSTRAINT "AnnouncementDismissal_announcementId_fkey" FOREIGN KEY ("announcementId") REFERENCES "BetaAnnouncement"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "AnnouncementDismissal" ADD CONSTRAINT "AnnouncementDismissal_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "GuidanceDismissal" ADD CONSTRAINT "GuidanceDismissal_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
